import pandas as pd
import numpy as np

# Datos de ejemplo
data = {
    "proyecto": ["PRY001", "PRY002", "PRY003", "PRY004"],
    "CPI":      [0.881,    0.963,    0.850,    0.948],
    "SPI":      [0.890,    0.969,    0.951,    0.956],
    "BAC":      [4.8e9,    12.5e9,   8.2e9,    6.4e9],
}
df = pd.DataFrame(data)
df["EAC"] = df["BAC"] / df["CPI"]
df["Desv_%"] = (df["EAC"] - df["BAC"]) / df["BAC"] * 100
print(df.round(3))
```

