def curva_s(mes, plazo):
    import math
    def s(t): return 1 / (1 + math.exp(-10 * (t/plazo - 0.5)))
    s0, s1 = s(0), s(plazo)
    return (s(mes) - s0) / (s1 - s0)

for mes in [1, 3, 6, 9, 12]:
    print(f"Mes {mes:2d}: {curva_s(mes, 12)*100:.1f}%")
